const defaultBuildDirectory = "./dist";
export const resolveBuildOptions = ({ buildDirectory = defaultBuildDirectory, staticDirectory = 'static', clientPathDirectory = 'client', serverPathDirectory = 'server', }) => {
    return {
        buildDirectory: buildDirectory,
        staticDirectory,
        manifestPathDirectory: '.vite',
        assetPathDirectory: 'assets',
        clientPathDirectory,
        serverPathDirectory,
        entryServerPath: 'entry.server.js',
    };
};
